window.initNavApp=function(){const config=window.navConfig;function validateConfig(){const errors=[];if(!config){errors.push('配置文件未找到');return errors}if(!config.categories||!Array.isArray(config.categories)){errors.push('categories 配置缺失或格式错误');return errors}if(config.categories.length===0){errors.push('categories 为空，请添加至少一个分类')}config.categories.forEach((category,index)=>{if(!category.name||typeof category.name!=='string'){errors.push(`分类#${index+1}缺少name属性`)}if(!category.items||!Array.isArray(category.items)){errors.push(`分类"${category.name || index}"的items配置缺失或格式错误`);return}if(category.items.length===0){console.warn(`⚠️分类"${category.name}"没有链接`)}category.items.forEach((item,itemIndex)=>{if(!item.name||typeof item.name!=='string'){errors.push(`分类"${category.name}"中的链接#${itemIndex+1}缺少name属性`)}})});return errors}function showError(message){const container=document.getElementById('cardContainer');if(container){container.innerHTML=`<div class="error-state"><i class="fa-solid fa-triangle-exclamation"></i><h3>配置错误</h3><p>${message}</p></div>`}console.error('配置错误:',message)}const validationErrors=validateConfig();if(validationErrors.length>0){showError(validationErrors.join('<br>'));return}(function(){const DOM={categoryList:document.getElementById('categoryList'),allCount:document.getElementById('allCount'),cardContainer:document.getElementById('cardContainer'),search:document.getElementById('search'),toggleLogo:document.getElementById('toggleLogo'),sidebar:document.getElementById('sidebar'),logoText:document.querySelector('.logo-text'),content:document.querySelector('.content'),themeToggle:document.getElementById('themeToggle'),themeIcon:document.querySelector('.theme-icon'),backToTopBtn:document.getElementById('backToTop'),contentHeader:document.getElementById('contentHeader'),contentHeaderIcon:document.getElementById('contentHeaderIcon'),contentHeaderTitle:document.getElementById('contentHeaderTitle'),categoryCount:document.getElementById('categoryCount'),linkCount:document.getElementById('linkCount'),footerIcp:document.getElementById('footerIcp')};const state={allLinks:[],categoryMap:{}};const utils={toggleSidebar:(isCollapsed)=>{DOM.sidebar.classList.toggle('collapsed',isCollapsed);DOM.logoText.style.opacity=isCollapsed?'0':'1';DOM.logoText.style.width=isCollapsed?'0':'auto';DOM.logoText.style.overflow=isCollapsed?'hidden':'visible'},getSystemTheme:()=>{return window.matchMedia('(prefers-color-scheme: dark)').matches?'dark':'light'},setTheme:(theme,animate=true)=>{if(animate){document.body.style.transition='background 0.4s ease, color 0.4s ease';document.querySelector('.header').style.transition='background 0.4s ease, box-shadow 0.4s ease';document.querySelector('.sidebar')?.style&&(document.querySelector('.sidebar').style.transition='background 0.4s ease, box-shadow 0.4s ease')}document.documentElement.setAttribute('data-theme',theme);DOM.themeIcon.className=theme==='dark'?'fa-solid fa-sun theme-icon':'fa-solid fa-moon theme-icon';if(animate){setTimeout(()=>{document.body.style.transition='';document.querySelector('.header').style.transition=''},400)}},getIconHtml:(link)=>{if(link.logo){return`<img src="${link.logo}"alt="${link.name}"class="card-logo-img"loading="lazy"referrerpolicy="no-referrer"onerror="this.style.display='none';this.nextElementSibling.style.display='flex';"><i class="fa-solid fa-globe"style="display:none;font-size:32px;color:#6366f1;align-items:center;justify-content:center;width:48px;height:48px;"></i>`}return link.icon?`<i class="${link.icon}"></i>`:'<i class="fa-solid fa-globe"></i>'},updateContentHeader:(category)=>{if(category==='all'){DOM.contentHeader.style.display='none'}else{const categoryInfo=config.categories.find(c=>c.name===category);DOM.contentHeader.style.display='flex';DOM.contentHeaderTitle.textContent=category;DOM.contentHeaderIcon.className=categoryInfo?.icon||'fa-solid fa-folder'}}};function init(){const validCategories=config.categories.filter(cat=>cat.name&&cat.items&&cat.items.length>0);if(validCategories.length===0){DOM.cardContainer.innerHTML='<div class="empty-state"><i class="fa-solid fa-folder-open"></i><p>暂无链接，请检查配置文件</p></div>';return}validCategories.forEach(category=>{state.categoryMap[category.name]=category;const validItems=category.items.filter(item=>item.name);validItems.forEach(link=>{state.allLinks.push({...link,category:category.name})})});config.categories=validCategories;renderCategories();renderCards(state.allLinks);bindEvents();initTheme();checkMobile();initFooterIcp();initSiteInfo()}function renderCategories(){config.categories.forEach(category=>{const item=document.createElement('a');item.className='category-item';item.dataset.category=category.name;item.innerHTML=`<i class="${category.icon || 'fa-solid fa-link'}"></i><span>${category.name}</span><span class="category-count">${category.items.length}</span>`;DOM.categoryList.appendChild(item)});DOM.allCount.textContent=`(${state.allLinks.length})`;if(DOM.categoryCount&&DOM.linkCount){DOM.categoryCount.textContent=config.categories.length;DOM.linkCount.textContent=state.allLinks.length}}function renderCards(links,showCategoryHeader=true){DOM.cardContainer.innerHTML='';if(links.length===0){DOM.cardContainer.innerHTML='<div class="empty-state"><i class="fa-solid fa-inbox"></i><p>暂无内容</p></div>';return}const groupedLinks=links.reduce((acc,link)=>{const category=link.category||'未分类';(acc[category]=acc[category]||[]).push(link);return acc},{});Object.entries(groupedLinks).forEach(([categoryName,categoryLinks],index)=>{const section=createCategorySection(categoryName,categoryLinks,index,showCategoryHeader);DOM.cardContainer.appendChild(section)})}function createCategorySection(name,links,sectionIndex,showCategoryHeader=true){const section=document.createElement('div');section.className='category-section';section.style.cssText=`opacity:0;transform:translateY(20px);animation:fadeInUp 0.4s ease ${sectionIndex*0.1}s forwards`;const iconClass=state.categoryMap[name]?.icon||'fa-solid fa-folder';if(showCategoryHeader){section.innerHTML=`<div class="category-header"><div class="category-header-left"><i class="${iconClass}"></i><h3 class="category-header-title">${name}</h3></div></div><div class="category-cards"></div>`}else{section.innerHTML=`<div class="category-cards"></div>`}const cardsContainer=section.querySelector('.category-cards');links.forEach((link,cardIndex)=>{cardsContainer.appendChild(createCard(link,sectionIndex,cardIndex))});return section}function createCard(link,sectionIndex,cardIndex){const card=document.createElement('a');card.className='card';if(link.url){card.href=link.url;card.target=link.target||'_blank';card.rel='noopener noreferrer'}card.title=link.subtitle||link.name;card.style.cssText=`opacity:0;transform:translateY(20px);animation:fadeInUp 0.3s ease ${(sectionIndex*0.1)+(cardIndex*0.05)}s forwards`;const tagHtml=link.tag?`<span class="card-tag">#${link.tag}</span>`:'';const subtitleHtml=link.subtitle?`<div class="card-desc">${link.subtitle}</div>`:'';card.innerHTML=`<div class="card-left"><div class="card-icon">${utils.getIconHtml(link)}</div></div><div class="card-middle"><div class="card-title">${link.name}</div>${subtitleHtml}</div><div class="card-right">${tagHtml}</div>`;return card}function bindEvents(){const isMobile=()=>window.innerWidth<=600;DOM.categoryList.addEventListener('click',(e)=>{const item=e.target.closest('.category-item');if(!item)return;document.querySelectorAll('.category-item').forEach(i=>i.classList.remove('active'));item.classList.add('active');const category=item.dataset.category;const filteredLinks=category==='all'?state.allLinks:state.allLinks.filter(l=>l.category===category);utils.updateContentHeader(category);renderCards(filteredLinks,category==='all')});DOM.search.addEventListener('input',(e)=>{const keyword=e.target.value.trim().toLowerCase();if(!keyword){renderCards(state.allLinks);DOM.contentHeader.style.display='none';return}const searchedLinks=state.allLinks.filter(link=>{const searchText=`${link.name}${link.subtitle||''}${link.keywords||''}`.toLowerCase();return searchText.includes(keyword)});renderCards(searchedLinks);DOM.contentHeader.style.display='none'});DOM.toggleLogo.addEventListener('click',()=>{if(isMobile()){DOM.sidebar.classList.toggle('mobile-visible')}else{const isCollapsed=DOM.sidebar.classList.toggle('collapsed');utils.toggleSidebar(isCollapsed)}});DOM.content.addEventListener('click',()=>{if(isMobile()&&DOM.sidebar.classList.contains('mobile-visible')){DOM.sidebar.classList.remove('mobile-visible')}});DOM.themeToggle.addEventListener('click',()=>{const currentTheme=document.documentElement.getAttribute('data-theme');let newTheme;let tooltipText;if(currentTheme==='dark'){newTheme='light';tooltipText='浅色模式'}else{newTheme='dark';tooltipText='深色模式'}localStorage.setItem('theme',newTheme);DOM.themeToggle.title=tooltipText;utils.setTheme(newTheme)});DOM.content.addEventListener('scroll',()=>{DOM.backToTopBtn.classList.toggle('visible',DOM.content.scrollTop>300)});DOM.backToTopBtn.addEventListener('click',()=>{DOM.content.scrollTo({top:0,behavior:'smooth'})});document.addEventListener('keydown',(e)=>{if((e.ctrlKey||e.metaKey)&&e.key==='k'){e.preventDefault();DOM.search.focus()}if(e.key==='Escape'){if(isMobile()&&DOM.sidebar.classList.contains('mobile-visible')){DOM.sidebar.classList.remove('mobile-visible')}if(document.activeElement===DOM.search){DOM.search.value='';DOM.search.dispatchEvent(new Event('input'));DOM.search.blur()}}});window.addEventListener('resize',checkMobile)}function initTheme(){const savedTheme=localStorage.getItem('theme');let tooltipText='深色模式';if(!savedTheme){utils.setTheme('dark',false)}else{tooltipText=savedTheme==='dark'?'深色模式':'浅色模式';utils.setTheme(savedTheme,false)}DOM.themeToggle.title=tooltipText}function checkMobile(){if(window.innerWidth<=600){DOM.sidebar.classList.add('collapsed')}else{DOM.sidebar.classList.remove('collapsed','mobile-visible');DOM.logoText.style.opacity='1';DOM.logoText.style.width='auto';DOM.logoText.style.overflow='visible'}}function initFooterIcp(){if(!DOM.footerIcp)return;const icpLink=DOM.footerIcp.querySelector('a');if(config.icp){icpLink.textContent=config.icp}else{DOM.footerIcp.style.display='none'}}function initSiteInfo(){if(config.title){document.title=config.title}if(DOM.logoText&&config.title){DOM.logoText.textContent=config.logoText}}init();window.NavApp={config,state,utils,renderCards}})()};